content.css:
.data-view-diagnostic {
  background: #f8fafc;
  box-sizing: border-box;
  color: #0f172a;
  font-family: "Segoe UI", Arial, sans-serif;
  font-size: 12px;
  height: 100%;
  overflow: hidden;
  padding: 14px;
  position: relative;
  width: 100%;
}
.data-view-diagnostic * {
  box-sizing: border-box;
}
.data-view-diagnostic button {
  font-family: inherit;
}
.data-view-diagnostic p {
  margin: 0;
}
.data-view-diagnostic .unit-summary-view,
.data-view-diagnostic .ugme-view {
  height: 100%;
  overflow: auto;
  padding: 2px 4px 52px;
  width: 100%;
}
.data-view-diagnostic .unit-summary-view h1 {
  color: #111827;
  font-size: 18px;
  font-weight: 800;
  line-height: 1.15;
  margin: 0 0 14px;
  text-transform: uppercase;
}
.data-view-diagnostic .unit-grid {
  display: grid;
  gap: 16px;
  grid-template-columns: repeat(2, minmax(280px, 1fr));
}
.data-view-diagnostic .unit-card {
  background: var(--unit-bg);
  border: 1px solid color-mix(in srgb, var(--unit-color) 28%, #ffffff);
  border-radius: 8px;
  box-shadow: 0 8px 20px rgba(15, 23, 42, 0.06);
  min-width: 0;
  overflow: hidden;
  padding: 14px;
  position: relative;
}
.data-view-diagnostic .unit-card::before {
  background: var(--unit-color);
  content: "";
  display: block;
  height: 4px;
  left: 0;
  position: absolute;
  right: 0;
  top: 0;
}
.data-view-diagnostic .unit-card-header {
  align-items: center;
  display: grid;
  gap: 10px;
  grid-template-columns: 34px minmax(0, 1fr) auto;
  margin-bottom: 12px;
  min-height: 38px;
}
.data-view-diagnostic .unit-card-icon {
  align-items: center;
  background: var(--unit-color);
  border-radius: 8px;
  color: #ffffff;
  display: flex;
  font-size: 12px;
  font-weight: 800;
  height: 34px;
  justify-content: center;
  width: 34px;
}
.data-view-diagnostic .unit-card-title-group {
  min-width: 0;
}
.data-view-diagnostic .unit-card-title {
  color: #0f172a;
  font-size: 17px;
  font-weight: 800;
  line-height: 1;
  margin: 0 0 4px;
}
.data-view-diagnostic .unit-card-subtitle {
  color: #475569;
  font-size: 11px;
  line-height: 1.2;
  overflow-wrap: anywhere;
}
.data-view-diagnostic .unit-card-detail-link {
  background: transparent;
  border: 0;
  color: var(--unit-color);
  cursor: pointer;
  font-size: 11px;
  font-weight: 700;
  padding: 4px 0;
  white-space: nowrap;
}
.data-view-diagnostic .unit-kpi-grid {
  display: grid;
  gap: 9px;
  grid-template-columns: repeat(2, minmax(0, 1fr));
}
.data-view-diagnostic .unit-kpi-cell {
  align-items: center;
  background: rgba(255, 255, 255, 0.82);
  border: 1px solid rgba(148, 163, 184, 0.22);
  border-radius: 7px;
  display: grid;
  gap: 8px;
  grid-template-columns: 28px minmax(0, 1fr);
  min-height: 58px;
  min-width: 0;
  padding: 8px;
}
.data-view-diagnostic .unit-kpi-icon {
  align-items: center;
  background: color-mix(in srgb, var(--unit-color) 16%, #ffffff);
  border-radius: 7px;
  color: var(--unit-color);
  display: flex;
  font-size: 10px;
  font-weight: 800;
  height: 28px;
  justify-content: center;
  width: 28px;
}
.data-view-diagnostic .unit-kpi-value {
  color: #111827;
  font-size: 16px;
  font-weight: 800;
  line-height: 1.1;
  overflow-wrap: anywhere;
}
.data-view-diagnostic .unit-kpi-label {
  color: #64748b;
  font-size: 10.5px;
  font-weight: 600;
  line-height: 1.15;
  margin-top: 3px;
  overflow-wrap: anywhere;
}
.data-view-diagnostic .floating-next-button {
  align-items: center;
  background: #0f172a;
  border: 0;
  border-radius: 999px;
  bottom: 16px;
  box-shadow: 0 12px 24px rgba(15, 23, 42, 0.22);
  color: #ffffff;
  cursor: pointer;
  display: flex;
  font-size: 12px;
  font-weight: 800;
  height: 38px;
  justify-content: center;
  padding: 0 14px;
  position: absolute;
  right: 16px;
  z-index: 5;
}
.data-view-diagnostic .ugme-view {
  padding-top: 0;
}
.data-view-diagnostic .ugme-back-button {
  background: #ffffff;
  border: 1px solid #cbd5e1;
  border-radius: 999px;
  color: #0f172a;
  cursor: pointer;
  font-size: 12px;
  font-weight: 800;
  margin: 0 0 12px;
  padding: 7px 12px;
}
.data-view-diagnostic .ugme-card {
  min-height: calc(100% - 46px);
}
.data-view-diagnostic .ugme-section-title {
  color: #0f172a;
  font-size: 14px;
  font-weight: 800;
  margin: 16px 0 10px;
}
.data-view-diagnostic .ugme-main-kpis {
  display: grid;
  gap: 10px;
  grid-template-columns: repeat(3, minmax(0, 1fr));
}
.data-view-diagnostic .ugme-group-grid {
  display: grid;
  gap: 10px;
  grid-template-columns: repeat(auto-fit, minmax(190px, 1fr));
  max-height: 340px;
  overflow: auto;
  padding-right: 2px;
}
.data-view-diagnostic .ugme-group-card {
  background: rgba(255, 255, 255, 0.84);
  border: 1px solid rgba(8, 145, 178, 0.18);
  border-radius: 7px;
  padding: 10px;
}
.data-view-diagnostic .ugme-group-card h4 {
  color: #0f172a;
  font-size: 12px;
  font-weight: 800;
  line-height: 1.2;
  margin: 0 0 8px;
}
.data-view-diagnostic .ugme-group-row {
  align-items: baseline;
  display: flex;
  gap: 8px;
  justify-content: space-between;
  padding: 4px 0;
}
.data-view-diagnostic .ugme-group-row span {
  color: #64748b;
  font-size: 10.5px;
  font-weight: 600;
}
.data-view-diagnostic .ugme-group-row strong {
  color: #0f172a;
  font-size: 12px;
  font-weight: 800;
  text-align: right;
}
.data-view-diagnostic .performance-mini {
  bottom: 6px;
  color: #64748b;
  font-size: 11px;
  position: absolute;
  right: 14px;
  z-index: 4;
}
.data-view-diagnostic .detail-modal-backdrop {
  align-items: center;
  background: rgba(15, 23, 42, 0.42);
  display: flex;
  inset: 0;
  justify-content: center;
  padding: 18px;
  position: absolute;
  z-index: 20;
}
.data-view-diagnostic .detail-modal {
  background: #ffffff;
  border-radius: 10px;
  box-shadow: 0 24px 60px rgba(15, 23, 42, 0.28);
  display: flex;
  flex-direction: column;
  max-height: calc(100% - 24px);
  max-width: 1300px;
  overflow: hidden;
  width: min(96%, 1300px);
}
.data-view-diagnostic .detail-modal-header {
  align-items: start;
  border-bottom: 1px solid #e2e8f0;
  display: flex;
  gap: 16px;
  justify-content: space-between;
  padding: 16px 18px 12px;
}
.data-view-diagnostic .detail-modal-header h2 {
  color: #0f172a;
  font-size: 18px;
  font-weight: 800;
  line-height: 1.15;
  margin: 0 0 4px;
}
.data-view-diagnostic .detail-modal-header p {
  color: #64748b;
  font-size: 12px;
}
.data-view-diagnostic .detail-modal-close {
  align-items: center;
  background: #f8fafc;
  border: 1px solid #cbd5e1;
  border-radius: 999px;
  color: #0f172a;
  cursor: pointer;
  display: flex;
  font-size: 12px;
  font-weight: 800;
  height: 30px;
  justify-content: center;
  width: 30px;
}
.data-view-diagnostic .detail-modal-toolbar {
  align-items: center;
  border-bottom: 1px solid #e2e8f0;
  display: flex;
  gap: 12px;
  justify-content: space-between;
  padding: 12px 18px;
}
.data-view-diagnostic .detail-search-input {
  border: 1px solid #cbd5e1;
  border-radius: 8px;
  color: #0f172a;
  font-size: 12px;
  min-width: 240px;
  outline: none;
  padding: 8px 10px;
  width: min(420px, 64%);
}
.data-view-diagnostic .detail-search-input:focus {
  border-color: #2563eb;
  box-shadow: 0 0 0 3px rgba(37, 99, 235, 0.12);
}
.data-view-diagnostic .detail-count {
  color: #64748b;
  font-size: 11px;
  font-weight: 700;
  white-space: nowrap;
}
.data-view-diagnostic .detail-table-scroller {
  flex: 1 1 auto;
  min-height: 220px;
  overflow: auto;
}
.data-view-diagnostic .detail-table {
  border-collapse: separate;
  border-spacing: 0;
  margin: 0;
  min-width: 1120px;
  table-layout: auto;
  width: 100%;
}
.data-view-diagnostic .detail-table th,
.data-view-diagnostic .detail-table td {
  border: 0;
  border-bottom: 1px solid #e2e8f0;
  color: #334155;
  font-size: 11.5px;
  line-height: 1.25;
  padding: 8px 10px;
  vertical-align: top;
  word-break: normal;
}
.data-view-diagnostic .detail-table th {
  background: #f8fafc;
  color: #0f172a;
  font-size: 11px;
  font-weight: 800;
  position: sticky;
  text-transform: uppercase;
  top: 0;
  z-index: 1;
}
.data-view-diagnostic .detail-pagination,
.data-view-diagnostic .detail-modal-footer {
  align-items: center;
  border-top: 1px solid #e2e8f0;
  display: flex;
  gap: 10px;
  justify-content: flex-end;
  padding: 10px 18px;
}
.data-view-diagnostic .detail-pagination {
  justify-content: center;
}
.data-view-diagnostic .detail-pagination span {
  color: #475569;
  font-size: 12px;
  font-weight: 700;
}
.data-view-diagnostic .detail-pagination button,
.data-view-diagnostic .detail-modal-footer button {
  background: #0f172a;
  border: 0;
  border-radius: 8px;
  color: #ffffff;
  cursor: pointer;
  font-size: 12px;
  font-weight: 800;
  padding: 8px 12px;
}
.data-view-diagnostic .detail-pagination button:disabled {
  background: #cbd5e1;
  cursor: default;
}
.data-view-diagnostic .loading-message {
  background: #ffffff;
  border: 1px solid #e2e8f0;
  border-radius: 8px;
  color: #475569;
  font-size: 12px;
  padding: 12px;
}
.data-view-diagnostic .metric-list {
  display: grid;
  grid-template-columns: max-content 1fr;
  margin: 0 0 12px;
  row-gap: 4px;
}
.data-view-diagnostic dt {
  font-weight: 600;
  margin: 0;
  padding-right: 12px;
}
.data-view-diagnostic dd {
  margin: 0;
}
.data-view-diagnostic table {
  border-collapse: collapse;
  margin-bottom: 12px;
  table-layout: fixed;
  width: 100%;
}
.data-view-diagnostic th,
.data-view-diagnostic td {
  border: 1px solid #d0d0d0;
  padding: 6px 8px;
  text-align: left;
  vertical-align: top;
  word-break: break-word;
}
.data-view-diagnostic th {
  background: #f3f3f3;
  font-weight: 600;
}
.data-view-diagnostic .summary-total-row td {
  background: #eeeeee;
  border-top: 2px solid #8a8a8a;
  font-weight: 600;
}
@media (max-width: 640px) {
  .data-view-diagnostic {
    padding: 10px;
  }
  .data-view-diagnostic .unit-grid {
    grid-template-columns: 1fr;
  }
  .data-view-diagnostic .unit-kpi-grid {
    grid-template-columns: 1fr;
  }
  .data-view-diagnostic .unit-card-header {
    grid-template-columns: 34px minmax(0, 1fr);
  }
  .data-view-diagnostic .unit-card-detail-link {
    grid-column: 2;
    justify-self: start;
  }
}
